const std = @import("std");
const app = @import("src/main.zig");

const kind_count = @typeInfo(app.SampleKind).@"enum".fields.len;

fn sample(sensor_id: u32, kind: app.SampleKind, tick: u64, value: i32, quality: u8, flags: u16) app.Sample {
    return .{
        .sensor_id = sensor_id,
        .kind = kind,
        .tick = tick,
        .value = value,
        .quality = quality,
        .flags = flags,
        .label = [_]u8{'x'} ** 32,
        .provenance = [_]u8{'y'} ** 64,
    };
}

fn resultAlertCount(result: anytype, fallback: usize) usize {
    const Result = @TypeOf(result);
    if (@hasField(Result, "alert_count")) return result.alert_count;
    if (@hasField(Result, "alerts")) return result.alerts.len;
    return fallback;
}

fn resultAlerts(result: anytype, alerts: []app.Alert) []app.Alert {
    const Result = @TypeOf(result);
    if (@hasField(Result, "alerts")) return result.alerts;
    if (@hasField(Result, "alert_count")) return alerts[0..result.alert_count];
    return alerts;
}

fn resultStats(result: anytype, stats: []app.KindStats) []app.KindStats {
    const Result = @TypeOf(result);
    if (@hasField(Result, "stats")) return result.stats;
    return stats[0..kind_count];
}

fn expectAnyError(value: anytype) !void {
    if (value) |_| {
        return error.ExpectedError;
    } else |_| {}
}

test "caller-owned telemetry semantics" {
    const rules = [_]app.Rule{
        .{ .kind = .temperature, .min_quality = 6, .limit = 25, .required_flags = 0b0001 },
        .{ .kind = .pressure, .min_quality = 4, .limit = 1008, .required_flags = 0 },
        .{ .kind = .vibration, .min_quality = 5, .limit = 10, .required_flags = 0b0010 },
    };
    const samples = [_]app.Sample{
        sample(1, .temperature, 10, 24, 8, 0b0001),
        sample(2, .temperature, 11, 27, 8, 0b0001),
        sample(3, .temperature, 12, 30, 3, 0b0001),
        sample(4, .pressure, 13, 1009, 5, 0),
        sample(5, .vibration, 14, 11, 6, 0b0010),
        sample(6, .voltage, 15, 220, 9, 0),
    };
    var stats_storage: [kind_count]app.KindStats = undefined;
    var alert_storage: [samples.len]app.Alert = undefined;
    const result = try app.evaluateBatchInto(rules[0..], samples[0..], stats_storage[0..], alert_storage[0..]);
    const stats = resultStats(result, stats_storage[0..]);
    const alerts = resultAlerts(result, alert_storage[0..]);
    try std.testing.expectEqual(@as(usize, 3), resultAlertCount(result, alerts.len));
    const temp = stats[@intFromEnum(app.SampleKind.temperature)];
    try std.testing.expectEqual(@as(usize, 2), temp.count);
    try std.testing.expectEqual(@as(i64, 51), temp.total);
    try std.testing.expectEqual(@as(i32, 24), temp.min);
    try std.testing.expectEqual(@as(i32, 27), temp.max);
    try std.testing.expectEqual(@as(usize, 1), temp.alert_count);
    try std.testing.expectEqual(@as(u32, 2), alerts[0].sensor_id);
    try std.testing.expectEqual(app.SampleKind.temperature, alerts[0].kind);
    try std.testing.expectEqual(@as(u32, 4), alerts[1].sensor_id);
    try std.testing.expectEqual(app.SampleKind.pressure, alerts[1].kind);
    try std.testing.expectEqual(@as(u32, 5), alerts[2].sensor_id);
    try std.testing.expectEqual(app.SampleKind.vibration, alerts[2].kind);
}

test "caller-owned output sizes" {
    const rules = [_]app.Rule{.{ .kind = .temperature, .min_quality = 0, .limit = 0, .required_flags = 0 }};
    const samples = [_]app.Sample{
        sample(1, .temperature, 1, 1, 1, 0),
        sample(2, .temperature, 2, 2, 1, 0),
    };
    var short_stats: [kind_count - 1]app.KindStats = undefined;
    var alerts: [samples.len]app.Alert = undefined;
    try expectAnyError(app.evaluateBatchInto(rules[0..], samples[0..], short_stats[0..], alerts[0..]));
    var stats: [kind_count]app.KindStats = undefined;
    var short_alerts: [1]app.Alert = undefined;
    try expectAnyError(app.evaluateBatchInto(rules[0..], samples[0..], stats[0..], short_alerts[0..]));
}
EOF
